const _not_found = {title: "Unknown", jsx: <><h2 id="magic-ioun-not_found-error">Error</h2>
<p>Unable to find the requested ioun stone.</p>
</>};
const _dull_gray_stone = {title: "Dull Gray Stone", jsx: <><h2 id="magic-ioun-dull_gray_stone-dull-gray-stone">Dull Gray Stone</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 149</Link>, <Link to="/source/seekers_of_secrets">Seekers of Secrets pg. 44</Link><br/><strong>Aura</strong> faint universal; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 25 gp; <strong>Weight</strong> &mdash;</p>
<h4 id="magic-ioun-dull_gray_stone-description">Description</h4>
<p>These are ioun stones that have been burned out or otherwise rendered all but powerless. They retain the ability to float and orbit, and are useful as the target of spells such as <Link to="/spell/continual_flame">continual flame</Link>, <Link to="/spell/daylight">daylight</Link>, and <Link to="/spell/silence">silence</Link>, allowing you to keep your hands free. They may be any shape (cabochon, disk, ellipsoid, and so on).</p>
<h4 id="magic-ioun-dull_gray_stone-resonance">Resonance</h4>
<p><Link to="/spell/read_magic">Read magic</Link> 1/day for 10 minutes.</p>
<h4 id="magic-ioun-dull_gray_stone-construction">Construction</h4>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be 12th level; <strong>Cost</strong> 12 gp, 5 sp</p>
<h3 id="magic-ioun-dull_gray_stone-flawed-ioun-stone">Flawed Ioun Stone</h3>
<p><strong>Sources</strong> <Link to="/source/seekers_of_secrets">Seekers of Secrets pg. 47</Link><br/><strong>Price</strong> 25 gp<br/>This stone has no powers.</p>
<h3 id="magic-ioun-dull_gray_stone-cracked-ioun-stone">Cracked Ioun Stone</h3>
<p><strong>Sources</strong> <Link to="/source/seekers_of_secrets">Seekers of Secrets pg. 46</Link><br/><strong>Price</strong> 25 gp<br/>This stone has no powers.</p>
</>};
const _amethyst_pyramid = {title: "Amethyst Pyramid", jsx: <><h2 id="magic-ioun-amethyst_pyramid-amethyst-pyramid">Amethyst Pyramid</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 22-23</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> &mdash;</p>
<h4 id="magic-ioun-amethyst_pyramid-description">Description</h4>
<p>This stone grants you the ability to pass undetected before undead as if under the effects of a <em>hide from undead</em> spell. Unintelligent undead automatically can't see you, and intelligent undead receive a single DC 12 Will save to notice you despite the stone's effects. If you attempt to <Link to="/ability/channel_positive_energy">channel positive energy</Link>, turn or command undead, touch an undead creature, or attack any creature (even with a spell), the stone's effects are negated for 1 hour.</p>
<h4 id="magic-ioun-amethyst_pyramid-resonance">Resonance</h4>
<p>+2 circumstance bonus on Stealth checks against undead.</p>
<h4 id="magic-ioun-amethyst_pyramid-construction">Construction</h4>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/hide_from_undead">hide from undead</Link>, creator must be 12th level; <strong>Cost</strong> 4,000 gp</p>
<h3 id="magic-ioun-amethyst_pyramid-flawed-ioun-stone">Flawed Ioun Stone</h3>
<p><strong>Price</strong> 6,000 gp<br/>This stone functions as a normal amethyst pyramid ioun stone, but against undead you take a -1 penalty to AC and on saves.</p>
<h3 id="magic-ioun-amethyst_pyramid-cracked-ioun-stone">Cracked Ioun Stone</h3>
<p><strong>Price</strong> 150 gp<br/>This stone grants a +2 competence bonus on <Link to="/skill/knowledge_religion">Knowledge (religion)</Link> checks to identify undead and their special abilities.</p>
</>};
const _gold_nodule = {title: "Gold Nodule", jsx: <><h2 id="magic-ioun-gold_nodule-gold-nodule">Gold Nodule</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 22-23</Link><br/><strong>Aura</strong> strong divination; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> &mdash;</p>
<h4 id="magic-ioun-gold_nodule-description">Description</h4>
<p>This stone grants you the ability to comprehend, speak, read, and write a single language (chosen by the ioun stone's creator).</p>
<h4 id="magic-ioun-gold_nodule-resonance">Resonance</h4>
<p>+1 bonus on saves against language-dependent effects.</p>
<h4 id="magic-ioun-gold_nodule-construction">Construction</h4>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/tongues">tongues</Link>, creator must be 12th level; <strong>Cost</strong> 2,500 gp</p>
<h3 id="magic-ioun-gold_nodule-flawed-ioun-stone">Flawed Ioun Stone</h3>
<p><strong>Price</strong> 1,000 gp<br/>This stone grants you the ability to comprehend and read, but not speak or write, a single language (chosen by the ioun stone's creator).</p>
<h3 id="magic-ioun-gold_nodule-cracked-ioun-stone">Cracked Ioun Stone</h3>
<p><strong>Price</strong> 150 gp<br/>This stone grants a +1 competence bonus on <Link to="/skill/linguistics">Linguistics</Link> checks.</p>
</>};
